# =========================
# Types
# =========================
CharState = Tuple[int, bool, int, int]       # pity, guaranteed, CR state, copies
WeaponState = Tuple[int, bool, int]          # pity, guaranteed_banner, fate_points
Phase0State = Tuple[int, bool, int]          # character before first copy
Phase1State = Tuple[int, bool, int, int, bool, int, int]  # saved character state + weapon state + weapon copies
Phase2State = Tuple[int, bool, int, int]     # character after weapon: pity, guaranteed, CR state, copies

EPS = 1e-12


# =========================
# Character banner
# =========================
class GenshinCharacterModel:
    """
    Modèle personnage basé sur la state machine fournie :
    - State 0 / 1 : 50% win, 50% lose -> garanti et state+1
    - State 2 : 50% win, state2_radiance_chance de radiance, reste en lose -> garanti state 3
    - State 3 : 100% radiance
    """
    def __init__(
        self,
        hard_pity_5: int = 90,
        base_rate_5: float = 0.006,
        five_star_rate_fn: Callable[[int], float] | None = None,
        state2_radiance_chance: float = 0.10,
    ) -> None:
        self.hard_pity_5 = hard_pity_5
        self.base_rate_5 = base_rate_5
        self.state2_radiance_chance = state2_radiance_chance
        self.five_star_rate_fn = five_star_rate_fn or self._default_five_star_rate
        self.rate_table = [self.five_star_rate_fn(i) for i in range(self.hard_pity_5)]

    def _default_five_star_rate(self, pity_5: int) -> float:
        if pity_5 >= self.hard_pity_5 - 1:
            return 1.0
        return self.base_rate_5

    @staticmethod
    def _win_target_state(state: int) -> int:
        return {0: 0, 1: 0, 2: 1, 3: 1}[state]

    @staticmethod
    def constellation_to_required_copies(constellation: int) -> int:
        if not (0 <= constellation <= 6):
            raise ValueError("La constellation doit être entre 0 et 6.")
        return constellation + 1

    def next_states(self, state: CharState, max_copies_tracked: int) -> List[Tuple[CharState, float]]:
        pity_5, guaranteed, machine_state, copies = state
        p_5 = self.rate_table[min(pity_5, self.hard_pity_5 - 1)]
        p_no_5 = 1.0 - p_5
        out: List[Tuple[CharState, float]] = []

        if p_no_5 > 0:
            out.append(((pity_5 + 1, guaranteed, machine_state, copies), p_no_5))

        if guaranteed:
            next_copies = min(copies + 1, max_copies_tracked)
            out.append(((0, False, machine_state, next_copies), p_5))
            return out

        if machine_state in (0, 1):
            next_copies = min(copies + 1, max_copies_tracked)
            win_state = self._win_target_state(machine_state)
            lose_state = min(machine_state + 1, 3)
            out.append(((0, False, win_state, next_copies), p_5 * 0.5))
            out.append(((0, True, lose_state, copies), p_5 * 0.5))
            return out

        if machine_state == 2:
            p_radiance = self.state2_radiance_chance
            p_win_direct = 0.5
            p_lose = max(0.0, 1.0 - p_win_direct - p_radiance)
            next_copies = min(copies + 1, max_copies_tracked)
            success_prob = p_5 * (p_win_direct + p_radiance)
            if success_prob > 0:
                out.append(((0, False, 1, next_copies), success_prob))
            if p_lose > 0:
                out.append(((0, True, 3, copies), p_5 * p_lose))
            return out

        next_copies = min(copies + 1, max_copies_tracked)
        out.append(((0, False, 1, next_copies), p_5))
        return out

    def distribution_after_wishes(
        self,
        wishes: int,
        starting_pity_5: int = 0,
        starting_guaranteed: bool = False,
        starting_state: int = 1,
        starting_copies: int = 0,
        max_copies_tracked: int = 7,
    ) -> Dict[int, float]:
        dist: Dict[CharState, float] = {
            (starting_pity_5, starting_guaranteed, starting_state, starting_copies): 1.0
        }

        for _ in range(wishes):
            new_dist: Dict[CharState, float] = defaultdict(float)
            for char_state, prob_state in dist.items():
                if prob_state < EPS:
                    continue
                for next_state, p in self.next_states(char_state, max_copies_tracked=max_copies_tracked):
                    total = prob_state * p
                    if total >= EPS:
                        new_dist[next_state] += total
            dist = dict(new_dist)

        result = {k: 0.0 for k in range(max_copies_tracked + 1)}
        for (_, _, _, copies), prob in dist.items():
            result[copies] += prob
        return result


# =========================
# Weapon banner
# =========================
class GenshinWeaponModel:
    """
    Bannière arme :
    - pity séparée
    - hard pity 80
    - sur 5★ non garanti :
        37.5% arme voulue
        37.5% autre arme bannière
        25% standard
    - avec 1 point de destin : prochaine 5★ = arme voulue
    """
    def __init__(
        self,
        hard_pity_5: int = 80,
        base_rate_5: float = 0.007,
        five_star_rate_fn: Callable[[int], float] | None = None,
    ) -> None:
        self.hard_pity_5 = hard_pity_5
        self.base_rate_5 = base_rate_5
        self.five_star_rate_fn = five_star_rate_fn or self._default_five_star_rate
        self.rate_table = [self.five_star_rate_fn(i) for i in range(self.hard_pity_5)]

    def _default_five_star_rate(self, pity_5: int) -> float:
        if pity_5 >= self.hard_pity_5 - 1:
            return 1.0
        return self.base_rate_5

    def next_states(self, state: WeaponState) -> List[Tuple[WeaponState, float, bool]]:
        pity_5, guaranteed_banner, fate_points = state
        p_5 = self.rate_table[min(pity_5, self.hard_pity_5 - 1)]
        p_no_5 = 1.0 - p_5
        out: List[Tuple[WeaponState, float, bool]] = []

        if p_no_5 > 0:
            out.append(((pity_5 + 1, guaranteed_banner, fate_points), p_no_5, False))

        if fate_points >= 1:
            out.append(((0, False, 0), p_5, True))
            return out

        if guaranteed_banner:
            out.append(((0, False, 0), p_5 * 0.5, True))
            out.append(((0, False, 1), p_5 * 0.5, False))
            return out

        out.append(((0, False, 0), p_5 * 0.375, True))
        out.append(((0, False, 1), p_5 * 0.375, False))
        out.append(((0, True, 1), p_5 * 0.25, False))
        return out


# =========================
# Pity functions
# =========================
def make_simple_rate_fn(base_rate: float, hard_pity: int):
    def rate_fn(pity_5: int) -> float:
        if pity_5 >= hard_pity - 1:
            return 1.0
        return base_rate
    return rate_fn


def make_soft_pity_rate_fn(
    base_rate: float,
    hard_pity: int,
    soft_start_pull_number: int,
    soft_growth_per_step: float,
):
    def rate_fn(pity_5: int) -> float:
        next_pull_number = pity_5 + 1
        if next_pull_number >= hard_pity:
            return 1.0
        if next_pull_number < soft_start_pull_number:
            return base_rate
        steps = next_pull_number - soft_start_pull_number
        rate = base_rate + steps * soft_growth_per_step
        return max(0.0, min(1.0, rate))
    return rate_fn


# =========================
# Helpers
# =========================
def format_percent(value: float) -> str:
    return f"{value * 100:.2f}%"


def probability_at_least_from_distribution(distribution: Dict[int, float], n: int) -> float:
    return sum(prob for copies, prob in distribution.items() if copies >= n)


def color_for_probability(value: float) -> str:
    if value > 0.99:
        return "#4FC3F7"   # bleu : >99%
    if value > 0.80:
        return "#66BB6A"   # vert : >80% à 99%
    if value > 0.60:
        return "#FFD54F"   # jaune : >60% à 80%
    if value > 0.40:
        return "#FFB74D"   # orange : >40% à 60%
    return "#EF5350"       # rouge : 0% à 40%


def badge_html(value: float) -> str:
    color = color_for_probability(value)
    return (
        f"<span style='background:{color}; color:#10141f; padding:0.26rem 0.62rem; "
        f"border-radius:0.62rem; font-weight:700; display:inline-block; min-width:98px; "
        f"text-align:center; box-shadow:0 0 18px rgba(255,255,255,0.06);'>"
        f"{format_percent(value)}</span>"
    )


def build_constellation_rows_from_distribution(distribution: Dict[int, float]) -> List[Dict[str, object]]:
    rows: List[Dict[str, object]] = []
    for c in range(7):
        needed = c + 1
        prob = probability_at_least_from_distribution(distribution, needed)
        rows.append(
            {
                "Constellation": f"C{c}",
                "Copies requises": needed,
                "Probabilité brute": prob,
                "Probabilité d'atteindre": format_percent(prob),
            }
        )
    return rows



def build_weapon_rows_from_distribution(distribution: Dict[int, float]) -> List[Dict[str, object]]:
    rows: List[Dict[str, object]] = []
    for r in range(1, 6):
        prob = probability_at_least_from_distribution(distribution, r)
        rows.append(
            {
                "Refinement": f"R{r}",
                "Copies requises": r,
                "Probabilité brute": prob,
                "Probabilité d'atteindre": format_percent(prob),
            }
        )
    return rows


def build_distribution_rows(distribution: Dict[int, float]) -> List[Dict[str, object]]:
    rows: List[Dict[str, object]] = []
    for copies in sorted(distribution):
        label = f"{copies} copie(s)" if copies < 7 else "7 copies ou plus"
        rows.append(
            {
                "Copies": label,
                "Probabilité brute": distribution[copies],
                "Probabilité": format_percent(distribution[copies]),
            }
        )
    return rows


