# =========================
# Optimized joint DP
# Strategy: character -> weapon -> constellations
# =========================

def joint_probability_character_weapon_constellations(
    total_wishes: int,
    target_constellation: int,
    target_refinement: int,
    character_model: GenshinCharacterModel,
    weapon_model: GenshinWeaponModel,
    char_pity: int,
    char_guaranteed: bool,
    char_state: int,
    current_copies: int,
    weapon_pity: int,
    weapon_guaranteed_banner: bool,
    weapon_fate_points: int,
    current_weapon_copies: int,
) -> float:
    target_total_copies = target_constellation + 1
    target_weapon_copies = target_refinement

    if current_copies >= target_total_copies and current_weapon_copies >= target_weapon_copies:
        return 1.0

    # Phase 0: get first character copy if not owned yet
    if current_copies >= 1:
        phase0: Dict[Phase0State, float] = {}
        phase1: Dict[Phase1State, float] = {
            (char_pity, char_guaranteed, char_state, weapon_pity, weapon_guaranteed_banner, min(1, weapon_fate_points), current_weapon_copies): 1.0
        }
    else:
        phase0 = {(char_pity, char_guaranteed, char_state): 1.0}
        phase1 = {}
    phase2: Dict[Phase2State, float] = {}
    finished = 0.0

    for _ in range(total_wishes):
        new_phase0: Dict[Phase0State, float] = defaultdict(float)
        new_phase1: Dict[Phase1State, float] = defaultdict(float)
        new_phase2: Dict[Phase2State, float] = defaultdict(float)
        new_finished = finished

        # Phase 0: get the character if not yet owned
        for (cp, cg, cs), prob_state in phase0.items():
            if prob_state < EPS:
                continue
            for next_state, p in character_model.next_states((cp, cg, cs, 0), max_copies_tracked=1):
                total = prob_state * p
                if total < EPS:
                    continue
                np, ng, ns, copies = next_state
                if copies >= 1:
                    new_phase1[(np, ng, ns, weapon_pity, weapon_guaranteed_banner, min(1, weapon_fate_points), current_weapon_copies)] += total
                else:
                    new_phase0[(np, ng, ns)] += total

        # Phase 1: pull weapon until target refinement reached
        for (saved_cp, saved_cg, saved_cs, wp, wg, wf, wcopies), prob_state in phase1.items():
            if prob_state < EPS:
                continue
            for next_state, p, got_target in weapon_model.next_states((wp, wg, wf)):
                total = prob_state * p
                if total < EPS:
                    continue
                nwp, nwg, nwf = next_state
                new_wcopies = min(5, wcopies + (1 if got_target else 0))
                if new_wcopies >= target_weapon_copies:
                    starting_post_weapon_copies = max(1, current_copies)
                    if target_total_copies <= starting_post_weapon_copies:
                        new_finished += total
                    else:
                        new_phase2[(saved_cp, saved_cg, saved_cs, starting_post_weapon_copies)] += total
                else:
                    new_phase1[(saved_cp, saved_cg, saved_cs, nwp, nwg, nwf, new_wcopies)] += total

        # Phase 2: finish constellations after the weapon objective is done
        for (cp, cg, cs, copies), prob_state in phase2.items():
            if prob_state < EPS:
                continue
            for next_state, p in character_model.next_states((cp, cg, cs, copies), max_copies_tracked=target_total_copies):
                total = prob_state * p
                if total < EPS:
                    continue
                np, ng, ns, ncopies = next_state
                if ncopies >= target_total_copies:
                    new_finished += total
                else:
                    new_phase2[(np, ng, ns, ncopies)] += total

        phase0 = dict(new_phase0)
        phase1 = dict(new_phase1)
        phase2 = dict(new_phase2)
        finished = new_finished

        if not phase0 and not phase1 and not phase2:
            break

    return finished



def joint_probability_constellations_then_weapon(
    total_wishes: int,
    target_constellation: int,
    target_refinement: int,
    character_model: GenshinCharacterModel,
    weapon_model: GenshinWeaponModel,
    char_pity: int,
    char_guaranteed: bool,
    char_state: int,
    current_copies: int,
    weapon_pity: int,
    weapon_guaranteed_banner: bool,
    weapon_fate_points: int,
    current_weapon_copies: int,
) -> float:
    target_total_copies = target_constellation + 1
    target_weapon_copies = target_refinement

    if current_copies >= target_total_copies and current_weapon_copies >= target_weapon_copies:
        return 1.0

    # Phase A: finish constellations first
    phase_char: Dict[Phase2State, float] = {(char_pity, char_guaranteed, char_state, current_copies): 1.0}
    # Phase B: then finish weapon refinement
    phase_weapon: Dict[Tuple[int, bool, int, int], float] = {}
    finished = 0.0

    for _ in range(total_wishes):
        new_phase_char: Dict[Phase2State, float] = defaultdict(float)
        new_phase_weapon: Dict[Tuple[int, bool, int, int], float] = defaultdict(float)
        new_finished = finished

        for (cp, cg, cs, copies), prob_state in phase_char.items():
            if prob_state < EPS:
                continue
            if copies >= target_total_copies:
                new_phase_weapon[(weapon_pity, weapon_guaranteed_banner, min(1, weapon_fate_points), current_weapon_copies)] += prob_state
                continue
            for next_state, p in character_model.next_states((cp, cg, cs, copies), max_copies_tracked=target_total_copies):
                total = prob_state * p
                if total < EPS:
                    continue
                np, ng, ns, ncopies = next_state
                if ncopies >= target_total_copies:
                    new_phase_weapon[(weapon_pity, weapon_guaranteed_banner, min(1, weapon_fate_points), current_weapon_copies)] += total
                else:
                    new_phase_char[(np, ng, ns, ncopies)] += total

        for (wp, wg, wf, wcopies), prob_state in phase_weapon.items():
            if prob_state < EPS:
                continue
            if wcopies >= target_weapon_copies:
                new_finished += prob_state
                continue
            for next_state, p, got_target in weapon_model.next_states((wp, wg, wf)):
                total = prob_state * p
                if total < EPS:
                    continue
                nwp, nwg, nwf = next_state
                new_wcopies = min(5, wcopies + (1 if got_target else 0))
                if new_wcopies >= target_weapon_copies:
                    new_finished += total
                else:
                    new_phase_weapon[(nwp, nwg, nwf, new_wcopies)] += total

        phase_char = dict(new_phase_char)
        phase_weapon = dict(new_phase_weapon)
        finished = new_finished

        if not phase_char and not phase_weapon:
            break

    return finished


# =========================
# Cached computations
# =========================
if st is not None:
    @st.cache_data(show_spinner=False)
    def cached_character_distribution(
        wishes: int,
        pity: int,
        guaranteed: bool,
        state: int,
        starting_copies: int,
        hard_pity: int,
        base_rate: float,
        mode: str,
        soft_start: int,
        soft_growth: float,
        state2_radiance_chance: float,
        max_copies_tracked: int,
    ) -> Dict[int, float]:
        if mode == "Soft Pity moyenne (approximative)":
            rate_fn = make_soft_pity_rate_fn(
                base_rate=base_rate,
                hard_pity=hard_pity,
                soft_start_pull_number=soft_start,
                soft_growth_per_step=soft_growth,
            )
        else:
            rate_fn = make_simple_rate_fn(base_rate=base_rate, hard_pity=hard_pity)

        model = GenshinCharacterModel(
            hard_pity_5=hard_pity,
            base_rate_5=base_rate,
            five_star_rate_fn=rate_fn,
            state2_radiance_chance=state2_radiance_chance,
        )
        return model.distribution_after_wishes(
            wishes=wishes,
            starting_pity_5=pity,
            starting_guaranteed=guaranteed,
            starting_state=state,
            starting_copies=starting_copies,
            max_copies_tracked=max_copies_tracked,
        )

    @st.cache_data(show_spinner=False)
    def cached_weapon_distribution(
        wishes: int,
        pity: int,
        guaranteed_banner: bool,
        fate_points: int,
        starting_copies: int,
        hard_pity: int,
        base_rate: float,
        mode: str,
        soft_start: int,
        soft_growth: float,
        max_copies_tracked: int,
    ) -> Dict[int, float]:
        if mode == "Soft Pity moyenne (approximative)":
            rate_fn = make_soft_pity_rate_fn(
                base_rate=base_rate,
                hard_pity=hard_pity,
                soft_start_pull_number=soft_start,
                soft_growth_per_step=soft_growth,
            )
        else:
            rate_fn = make_simple_rate_fn(base_rate=base_rate, hard_pity=hard_pity)

        model = GenshinWeaponModel(
            hard_pity_5=hard_pity,
            base_rate_5=base_rate,
            five_star_rate_fn=rate_fn,
        )
        dist = {(pity, guaranteed_banner, min(1, fate_points), starting_copies): 1.0}
        for _ in range(wishes):
            new_dist: Dict[Tuple[int, bool, int, int], float] = defaultdict(float)
            for (wp, wg, wf, wc), prob_state in dist.items():
                if prob_state < EPS:
                    continue
                for next_state, p, got_target in model.next_states((wp, wg, wf)):
                    total = prob_state * p
                    if total < EPS:
                        continue
                    nwp, nwg, nwf = next_state
                    nwc = min(max_copies_tracked, wc + (1 if got_target else 0))
                    new_dist[(nwp, nwg, nwf, nwc)] += total
            dist = dict(new_dist)
        result = {k: 0.0 for k in range(max_copies_tracked + 1)}
        for (_, _, _, copies), prob in dist.items():
            result[copies] += prob
        return result

    @st.cache_data(show_spinner=False)
    def cached_joint_probability(
        total_wishes: int,
        target_constellation: int,
        target_refinement: int,
        strategy: str,
        char_pity: int,
        char_guaranteed: bool,
        char_state: int,
        current_copies: int,
        char_hard_pity: int,
        char_base_rate: float,
        weapon_pity: int,
        weapon_guaranteed_banner: bool,
        weapon_fate_points: int,
        weapon_hard_pity: int,
        weapon_base_rate: float,
        current_weapon_copies: int,
        mode: str,
        soft_start_char: int,
        soft_growth_char: float,
        soft_start_weapon: int,
        soft_growth_weapon: float,
        state2_radiance_chance: float,
    ) -> float:
        if mode == "Soft Pity moyenne (approximative)":
            char_rate_fn = make_soft_pity_rate_fn(
                base_rate=char_base_rate,
                hard_pity=char_hard_pity,
                soft_start_pull_number=soft_start_char,
                soft_growth_per_step=soft_growth_char,
            )
            weapon_rate_fn = make_soft_pity_rate_fn(
                base_rate=weapon_base_rate,
                hard_pity=weapon_hard_pity,
                soft_start_pull_number=soft_start_weapon,
                soft_growth_per_step=soft_growth_weapon,
            )
        else:
            char_rate_fn = make_simple_rate_fn(base_rate=char_base_rate, hard_pity=char_hard_pity)
            weapon_rate_fn = make_simple_rate_fn(base_rate=weapon_base_rate, hard_pity=weapon_hard_pity)

        character_model = GenshinCharacterModel(
            hard_pity_5=char_hard_pity,
            base_rate_5=char_base_rate,
            five_star_rate_fn=char_rate_fn,
            state2_radiance_chance=state2_radiance_chance,
        )
        weapon_model = GenshinWeaponModel(
            hard_pity_5=weapon_hard_pity,
            base_rate_5=weapon_base_rate,
            five_star_rate_fn=weapon_rate_fn,
        )
        if strategy == "constellations_then_weapon":
            return joint_probability_constellations_then_weapon(
                total_wishes=total_wishes,
                target_constellation=target_constellation,
                target_refinement=target_refinement,
                character_model=character_model,
                weapon_model=weapon_model,
                char_pity=char_pity,
                char_guaranteed=char_guaranteed,
                char_state=char_state,
                current_copies=current_copies,
                weapon_pity=weapon_pity,
                weapon_guaranteed_banner=weapon_guaranteed_banner,
                weapon_fate_points=weapon_fate_points,
                current_weapon_copies=current_weapon_copies,
            )
        return joint_probability_character_weapon_constellations(
            total_wishes=total_wishes,
            target_constellation=target_constellation,
            target_refinement=target_refinement,
            character_model=character_model,
            weapon_model=weapon_model,
            char_pity=char_pity,
            char_guaranteed=char_guaranteed,
            char_state=char_state,
            current_copies=current_copies,
            weapon_pity=weapon_pity,
            weapon_guaranteed_banner=weapon_guaranteed_banner,
            weapon_fate_points=weapon_fate_points,
            current_weapon_copies=current_weapon_copies,
        )


